            aCross = (RotL64(aExpandLaneC[((S_BLOCK1 - aIndex + 4250U)) & S_BLOCK1], 13U) ^ RotL64(aExpandLaneD[((S_BLOCK1 - aIndex + 1415U)) & S_BLOCK1], 23U));
            aCross ^= RotL64(aEarthLaneC[((S_BLOCK1 - aIndex + 3600U)) & S_BLOCK1], 54U);
